function olb(i){
  const p=products[i];
  document.getElementById('lb-img').innerHTML=svgs[p.svg]||'';
  document.getElementById('lb-nm').textContent=p.name;
  document.getElementById('lb-pr').textContent=p.price;
  document.getElementById('lb-wa').href=wa(`Olá! Vim pelo site Careca Store e tenho interesse em: ${p.name} (${p.price}). Ainda tem disponível?`);
  document.getElementById('lb').classList.add('on');
  document.body.style.overflow='hidden';
}
function clb(){
  document.getElementById('lb').classList.remove('on');
  document.body.style.overflow='';
}
document.getElementById('lb').addEventListener('click',e=>{if(e.target===document.getElementById('lb'))clb()});

