function popularCategorias(){
  const select=document.getElementById('filtro-cat');
  [...new Set(products.map(p=>p.cat))].sort((a,b)=>a.localeCompare(b,'pt-BR')).forEach(cat=>{
    const op=document.createElement('option');
    op.value=cat;
    op.textContent=cat;
    select.appendChild(op);
  });
}

function cardProduto(p,i,bm){
  const c=document.createElement('div');
  c.className='pc';
  c.innerHTML=`
    ${p.badge?`<div class="bdg ${p.badge}">${bm[p.badge]}</div>`:''}
    <div class="pi" onclick="olb(${i})">
      ${svgs[p.svg]||`<svg viewBox="0 0 300 200"><rect width="300" height="200" fill="#1a1a2a"/><text x="150" y="105" text-anchor="middle" fill="#00e5ff" font-size="40">🖥️</text></svg>`}
      <div class="pi-ov"><span>🔍 Ver Foto</span></div>
    </div>
    <div class="pinfo">
      <div class="pct">${p.cat}</div>
      <div class="pnm">${p.name}</div>
      <div class="ppr"><span class="prn">${p.price}</span><span class="prw">${p.old}</span></div>
      <a href="${wa(`Olá! Vim pelo site Careca Store e tenho interesse em: ${p.name} (${p.price}). Ainda tem disponível?`)}" class="wb" target="_blank" rel="noopener noreferrer">💬 Comprar pelo WhatsApp</a>
    </div>`;
  return c;
}

function renderProducts(){
  const g=document.getElementById('pgrid');
  const busca=(document.getElementById('busca').value||'').trim().toLowerCase();
  const cat=document.getElementById('filtro-cat').value;
  const bm={hot:'🔥 HOT',new:'✨ NOVO',sale:'🏷 OFERTA'};
  g.innerHTML='';
  const filtrados=products.filter(p=>{
    const alvo=`${p.cat} ${p.name} ${p.price}`.toLowerCase();
    const matchBusca=!busca || alvo.includes(busca);
    const matchCat=!cat || p.cat===cat;
    return matchBusca && matchCat;
  });
  document.getElementById('contador').textContent=`${filtrados.length} produto${filtrados.length===1?'':'s'}`;
  if(!filtrados.length){
    g.innerHTML='<div class="empty">Nenhum produto encontrado com esse filtro.</div>';
    return;
  }
  filtrados.forEach(p=>g.appendChild(cardProduto(p, products.indexOf(p), bm)));
}

function renderVideos(){
  const g=document.getElementById('vgrid');
  featuredVideos.forEach(v=>{
    const c=document.createElement('div');
    c.className='vc';
    c.innerHTML=`
      <video controls muted playsinline preload="metadata">
        <source src="${v.file}" type="video/mp4">
        Seu navegador não suporta vídeo HTML5.
      </video>
      <div class="vinfo">
        <div class="vtag">${v.tag}</div>
        <div class="vnm">${v.name}</div>
        <div class="vds">${v.desc}</div>
      </div>`;
    g.appendChild(c);
  });
}

popularCategorias();
renderProducts();
renderVideos();
document.getElementById('busca').addEventListener('input', renderProducts);
document.getElementById('filtro-cat').addEventListener('change', renderProducts);
